// SQL helpers
function sq(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}
function sj(v) {
  return v == null ? 'NULL' : "'" + JSON.stringify(v).replace(/'/g, "''") + "'::jsonb";
}
function si(v) {
  return v == null ? 'NULL' : parseInt(v, 10);
}

// Basic trace data from the webhook body
const webhook = $('Webhook: Enrich Trace').first().json.body;
const traceId = webhook.trace_id;

// Execution data from HTTP Request
const execResponse = $input.first().json;
const runData = execResponse?.data?.resultData?.runData || {};

// Extract tool calls + Think steps
let toolCalls = null;
let thinkSteps = null;
let dealId = null;
let iterationCount = null;
let totalDurationMs = null;
let toolsCalledCount = 0;
let ragChunks = null;
let promptTokens = null;
let completionToks = null;
let totalTokens = null;

const agentRun = runData['AI Agent']?.[0];
if (agentRun) {
  totalDurationMs = agentRun.executionTime || null;
  const subExec = agentRun.metadata?.subNodeExecutionData || {};
  const actions = subExec.actions || [];

  // iterationCount lives in the metadata array as a plain string key
  // but the actual value is on the agent run metadata directly
  const metaArr = subExec.metadata || [];
  if (Array.isArray(metaArr)) {
    // n8n stores this as field names; actual count is elsewhere
    iterationCount = null;
  } else if (typeof metaArr === 'object') {
    iterationCount = metaArr.iterationCount || null;
  }

  if (actions.length > 0) {
    const calls = [];
    for (const a of actions) {
      const act = a.action || {};
      const nodeName = act.nodeName || '';
      // Think tool does NOT appear in the actions array — skip check here
      calls.push({ tool: nodeName, input: act.input || {}, duration_ms: null });
      if (act.input?.deal_id && !dealId) dealId = act.input.deal_id;
    }
    if (calls.length > 0) toolCalls = calls;
    toolsCalledCount = calls.length;
  }
}

// ── Think tool extraction ──
// The Think tool appears as a top-level node in runData (not in the agent actions array).
// Its output is at data.ai_tool[0][0].json.response per run.
const thinkRuns = runData['Think'] || [];
if (thinkRuns.length > 0) {
  const thinks = [];
  for (const run of thinkRuns) {
    const aiToolOutput = run?.data?.ai_tool;
    if (aiToolOutput && aiToolOutput[0] && aiToolOutput[0].length > 0) {
      for (const item of aiToolOutput[0]) {
        const response = item?.json?.response;
        if (response) {
          thinks.push({
            step: thinks.length + 1,
            content: response,
          });
        }
      }
    }
  }
  if (thinks.length > 0) thinkSteps = thinks;
}

// ── deal_id fallback: extract from tool nodes in runData ──
if (!dealId) {
  // Check tool nodes that have ai_tool output for deal_id in their input
  for (const [nodeName, runs] of Object.entries(runData)) {
    if (dealId) break;
    if (!nodeName.startsWith('Tool:')) continue;
    for (const run of runs) {
      const items = run?.data?.ai_tool?.[0] || [];
      for (const item of items) {
        const did = item?.json?.deal_id;
        if (did) { dealId = did; break; }
      }
      if (dealId) break;
    }
  }
}

// Extract RAG chunks
const ragNode = runData['Tool: search_deal_rag'];
if (ragNode) {
  const chunks = [];
  for (const run of ragNode) {
    const result = run?.data?.ai_tool?.[0]?.[0]?.json?.result;
    if (result) {
      chunks.push({ query: 'search_deal_rag', top_preview: String(result).substring(0, 300), chunks_returned: (String(result).match(/##/g) || []).length });
    }
  }
  if (chunks.length > 0) ragChunks = chunks;
}

// Extract token usage
const claudeRuns = runData['Claude Sonnet 4.6'] || [];
if (claudeRuns.length > 0) {
  let pTotal = 0, cTotal = 0;
  for (const cr of claudeRuns) {
    const tu = cr?.data?.ai_languageModel?.[0]?.[0]?.json?.tokenUsage;
    if (tu) { pTotal += tu.promptTokens || 0; cTotal += tu.completionTokens || 0; }
  }
  promptTokens = pTotal;
  completionToks = cTotal;
  totalTokens = pTotal + cTotal;
}

// Build UPDATE SQL to enrich the existing row
const sql = `
UPDATE agent_traces SET
  deal_id = ${sq(dealId)},
  think_steps = ${sj(thinkSteps)},
  tool_calls = ${sj(toolCalls)},
  rag_chunks = ${sj(ragChunks)},
  prompt_tokens = ${si(promptTokens)},
  completion_tokens = ${si(completionToks)},
  total_tokens = ${si(totalTokens)},
  total_duration_ms = ${si(totalDurationMs)},
  iteration_count = ${si(iterationCount)},
  tools_called_count = ${si(toolsCalledCount)}
WHERE id = ${si(traceId)};`.trim();

return [{ json: { update_sql: sql } }];

